const itens = $input.all();

const texto = itens.map((item, i) => {
  const d = item.json;
  return `${i + 1}. ${d.title} | ${d.contentSnippet} | Link: ${d.link}`;
}).join(' /// ');

return [{ json: { noticias: texto } }];

const relatorio = $input.first().json.relatorio;

return [{
  json: { relatorio },
  binary: {
    data: {
      data: Buffer.from(relatorio).toString('base64'),
      mimeType: 'text/markdown',
      fileName: 'relatorio_semanal.md'
    }
  }
}];

const itens = $input.all();
const triagem = itens[0].json.choices[0].message.content.replace(/"/g, '').replace(/\n/g, ' ');
const tendencias = itens[1].json.choices[0].message.content.replace(/"/g, '').replace(/\n/g, ' ');
const oportunidades = itens[2].json.choices[0].message.content.replace(/"/g, '').replace(/\n/g, ' ');

return [{ json: { triagem, tendencias, oportunidades } }];
